// MARK: - Custom Errors

enum DataSecurityError: Error, LocalizedError {
    case encryptionFailed(status: CCCryptorStatus)
    case decryptionFailed(status: CCCryptorStatus)
    case keyGenerationFailed
    case keychainSaveFailed(status: OSStatus)
    case keychainReadFailed(status: OSStatus)
    case keychainDeleteFailed(status: OSStatus)
    case invalidData
    case encodingFailed
    case decodingFailed
    
    var errorDescription: String? {
        switch self {
        case .encryptionFailed(let status):
            return "Encryption failed with status: \(status)"
        case .decryptionFailed(let status):
            return "Decryption failed with status: \(status)"
        case .keyGenerationFailed:
            return "Failed to generate encryption key"
        case .keychainSaveFailed(let status):
            return "Keychain save failed with status: \(status)"
        case .keychainReadFailed(let status):
            return "Keychain read failed with status: \(status)"
        case .keychainDeleteFailed(let status):
            return "Keychain delete failed with status: \(status)"
        case .invalidData:
            return "Invalid data provided"
        case .encodingFailed:
            return "Failed to encode data"
        case .decodingFailed:
            return "Failed to decode data"
        }
    }
}

