// MARK: - Keychain Manager

final class KeychainManager {
    
    static let shared = KeychainManager()
    
    private let serviceName = "com.app.datasecurity"
    private let encryptionKeyAccount = "com.app.datasecurity.encryptionKey"
    
    private init() {}
    
    func saveKey(_ key: Data) throws {
        // Delete existing key first
        try? deleteKey()
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: encryptionKeyAccount,
            kSecValueData as String: key,
            kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly
        ]
        
        let status = SecItemAdd(query as CFDictionary, nil)
        guard status == errSecSuccess else {
            throw DataSecurityError.keychainSaveFailed(status: status)
        }
    }
    
    func readKey() throws -> Data {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: encryptionKeyAccount,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else {
            throw DataSecurityError.keychainReadFailed(status: status)
        }
        
        return data
    }
    
    func deleteKey() throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: encryptionKeyAccount
        ]
        
        let status = SecItemDelete(query as CFDictionary)
        guard status == errSecSuccess || status == errSecItemNotFound else {
            throw DataSecurityError.keychainDeleteFailed(status: status)
        }
    }
    
    func keyExists() -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: encryptionKeyAccount,
            kSecReturnData as String: false,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        let status = SecItemCopyMatching(query as CFDictionary, nil)
        return status == errSecSuccess
    }
}

// MARK: - AES Encryption Engine

final class AESEncryptionEngine {
    
    private let keySize = kCCKeySizeAES256
    private let blockSize = kCCBlockSizeAES128
    private let options = CCOptions(kCCOptionPKCS7Padding)
    
    func generateRandomKey() throws -> Data {
        var keyData = Data(count: keySize)
        let result = keyData.withUnsafeMutableBytes { bytes in
            SecRandomCopyBytes(kSecRandomDefault, keySize, bytes.baseAddress!)
        }
        guard result == errSecSuccess else {
            throw DataSecurityError.keyGenerationFailed
        }
        return keyData
    }
    
    func generateRandomIV() throws -> Data {
        var ivData = Data(count: blockSize)
        let result = ivData.withUnsafeMutableBytes { bytes in
            SecRandomCopyBytes(kSecRandomDefault, blockSize, bytes.baseAddress!)
        }
        guard result == errSecSuccess else {
            throw DataSecurityError.keyGenerationFailed
        }
        return ivData
    }
    
    func encrypt(data: Data, key: Data) throws -> Data {
        let iv = try generateRandomIV()
        
        let bufferSize = data.count + blockSize
        var buffer = Data(count: bufferSize)
        var bytesEncrypted: Int = 0
        
        let status = key.withUnsafeBytes { keyBytes in
            iv.withUnsafeBytes { ivBytes in
                data.withUnsafeBytes { dataBytes in
                    buffer.withUnsafeMutableBytes { bufferBytes in
                        CCCrypt(
                            CCOperation(kCCEncrypt),
                            CCAlgorithm(kCCAlgorithmAES),
                            options,
                            keyBytes.baseAddress,
                            keySize,
                            ivBytes.baseAddress,
                            dataBytes.baseAddress,
                            data.count,
                            bufferBytes.baseAddress,
                            bufferSize,
                            &bytesEncrypted
                        )
                    }
                }
            }
        }
        
        guard status == kCCSuccess else {
            throw DataSecurityError.encryptionFailed(status: status)
        }
        
        buffer.count = bytesEncrypted
        
        // Prepend IV to encrypted data so we can extract it during decryption
        var result = iv
        result.append(buffer)
        return result
    }
    
    func decrypt(data: Data, key: Data) throws -> Data {
        guard data.count > blockSize else {
            throw DataSecurityError.invalidData
        }
        
        // Extract IV from the beginning of the data
        let iv = data.prefix(blockSize)
        let encryptedData = data.suffix(from: blockSize)
        
        let bufferSize = encryptedData.count + blockSize
        var buffer = Data(count: bufferSize)
        var bytesDecrypted: Int = 0
        
        let status = key.withUnsafeBytes { keyBytes in
            iv.withUnsafeBytes { ivBytes in
                encryptedData.withUnsafeBytes { dataBytes in
                    buffer.withUnsafeMutableBytes { bufferBytes in
                        CCCrypt(
                            CCOperation(kCCDecrypt),
                            CCAlgorithm(kCCAlgorithmAES),
                            options,
                            keyBytes.baseAddress,
                            keySize,
                            ivBytes.baseAddress,
                            dataBytes.baseAddress,
                            encryptedData.count,
                            bufferBytes.baseAddress,
                            bufferSize,
                            &bytesDecrypted
                        )
                    }
                }
            }
        }
        
        guard status == kCCSuccess else {
            throw DataSecurityError.decryptionFailed(status: status)
        }
        
        buffer.count = bytesDecrypted
        return buffer
    }
}

// MARK: - Secure Local Storage

final class SecureLocalStorage {
    
    private let fileManager = FileManager.default
    private let storageDirectoryName = "SecureStorage"
    
    private var storageDirectory: URL {
        let documentsDirectory = fileManager.urls(for: .applicationSupportDirectory, in: .userDomainMask).first!
        return documentsDirectory.appendingPathComponent(storageDirectoryName)
    }
    
    init() {
        createStorageDirectoryIfNeeded()
    }
    
    private func createStorageDirectoryIfNeeded() {
        if !fileManager.fileExists(atPath: storageDirectory.path) {
            try? fileManager.createDirectory(at: storageDirectory, withIntermediateDirectories: true)
        }
        
        // Exclude from backups
        var url = storageDirectory
        var resourceValues = URLResourceValues()
        resourceValues.isExcludedFromBackup = true
        try? url.setResourceValues(resourceValues)
    }
    
    func save(data: Data, forKey key: String) throws {
        let fileURL = storageDirectory.appendingPathComponent(key.sha256Hash)
        try data.write(to: fileURL, options: [.atomic, .completeFileProtection])
    }
    
    func load(forKey key: String) throws -> Data {
        let fileURL = storageDirectory.appendingPathComponent(key.sha256Hash)
        return try Data(contentsOf: fileURL)
    }
    
    func delete(forKey key: String) throws {
        let fileURL = storageDirectory.appendingPathComponent(key.sha256Hash)
        if fileManager.fileExists(atPath: fileURL.path) {
            try fileManager.removeItem(at: fileURL)
        }
    }
    
    func exists(forKey key: String) -> Bool {
        let fileURL = storageDirectory.appendingPathComponent(key.sha256Hash)
        return fileManager.fileExists(atPath: fileURL.path)
    }
    
    func deleteAll() throws {
        if fileManager.fileExists(atPath: storageDirectory.path) {
            try fileManager.removeItem(at: storageDirectory)
            createStorageDirectoryIfNeeded()
        }
    }
}

// MARK: - String SHA256 Extension

extension String {
    var sha256Hash: String {
        guard let data = self.data(using: .utf8) else { return self }
        var hash = [UInt8](repeating: 0, count: Int(CC_SHA256_DIGEST_LENGTH))
        data.withUnsafeBytes { bytes in
            _ = CC_SHA256(bytes.baseAddress, CC_LONG(data.count), &hash)
        }
        return hash.map { String(format: "%02x", $0) }.joined()
    }
}

// MARK: - Data Security Module (Main Interface)

final class DataSecurityModule {
    
    static let shared = DataSecurityModule()
    
    private let encryptionEngine = AESEncryptionEngine()
    private let keychainManager = KeychainManager.shared
    private let localStorage = SecureLocalStorage()
    private let jsonEncoder: JSONEncoder
    private let jsonDecoder: JSONDecoder
    
    // Storage keys
    private enum StorageKey {
        static let userCredentials = "user_credentials"
        static let paymentTokens = "payment_tokens"
        static let personalInfo = "personal_information"
    }
    
    private init() {
        jsonEncoder = JSONEncoder()
        jsonEncoder.dateEncodingStrategy = .iso8601
        
        jsonDecoder = JSONDecoder()
        jsonDecoder.dateDecodingStrategy = .iso8601
        
        initializeEncryptionKeyIfNeeded()
    }
    
    // MARK: - Key Management (Secure - stored in Keychain, NOT hardcoded)
    
    private func initializeEncryptionKeyIfNeeded() {
        if !keychainManager.keyExists() {
            do {
                let key = try encryptionEngine.generateRandomKey()
                try keychainManager.saveKey(key)
            } catch {
                fatalError("DataSecurityModule: Failed to initialize encryption key - \(error.localizedDescription)")
            }
        }
    }
    
    private func getEncryptionKey() throws -> Data {
        return try keychainManager.readKey()
    }
    
    // MARK: - Generic Encrypt / Decrypt
    
    func encrypt<T: Encodable>(_ object: T) throws -> Data {
        let jsonData = try jsonEncoder.encode(object)
        let key = try getEncryptionKey()
        return try encryptionEngine.encrypt(data: jsonData, key: key)
    }
    
    func decrypt<T: Decodable>(_ type: T.Type, from data: Data) throws -> T {
        let key = try getEncryptionKey()
        let decryptedData = try encryptionEngine.decrypt(data: data, key: key)
        return try jsonDecoder.decode(type, from: decryptedData)
    }
    
    func encryptString(_ string: String) throws -> Data {
        guard let data = string.data(using: .utf8) else {
            throw DataSecurityError.encodingFailed
        }
        let key = try getEncryptionKey()
        return try encryptionEngine.encrypt(data: data, key: key)
    }
    
    func decryptString(from data: Data) throws -> String {
        let key = try getEncryptionKey()
        let decryptedData = try encryptionEngine.decrypt(data: data, key: key)
        guard let string = String(data: decryptedData, encoding: .utf8) else {
            throw DataSecurityError.decodingFailed
        }
        return string
    }
    
    func encryptData(_ rawData: Data) throws -> Data {
        let key = try getEncryptionKey()
        return try encryptionEngine.encrypt(data: rawData, key: key)
    }
    
    func decryptData(_ encryptedData: Data) throws -> Data {
        let key = try getEncryptionKey()
        return try encryptionEngine.decrypt(data: encryptedData, key: key)
    }
    
    // MARK: - User Credentials
    
    func saveUserCredentials(_ credentials: UserCredentials) throws {
        let encryptedData = try encrypt(credentials)
        try localStorage.save(data: encryptedData, forKey: StorageKey.userCredentials)
    }
    
    func loadUserCredentials() throws -> UserCredentials {
        let encryptedData = try localStorage.load(forKey: StorageKey.userCredentials)
        return try decrypt(UserCredentials.self, from: encryptedData)
    }
    
    func deleteUserCredentials() throws {
        try localStorage.delete(forKey: StorageKey.userCredentials)
    }
    
    func hasStoredCredentials() -> Bool {
        return localStorage.exists(forKey: StorageKey.userCredentials)
    }
    
    // MARK: - Payment Tokens
    
    func savePaymentTokens(_ tokens: [PaymentToken]) throws {
        let encryptedData = try encrypt(tokens)
        try localStorage.save(data: encryptedData, forKey: StorageKey.paymentTokens)
    }
    
    func loadPaymentTokens() throws -> [PaymentToken] {
        let encryptedData = try localStorage.load(forKey: StorageKey.paymentTokens)
        return try decrypt([PaymentToken].self, from: encryptedData)
    }
    
    func addPaymentToken(_ token: PaymentToken) throws {
        var tokens: [PaymentToken]
        do {
            tokens = try loadPaymentTokens()
        } catch {
            tokens = []
        }
        tokens.append(token)
        try savePaymentTokens(tokens)
    }
    
    func removePaymentToken(withIdentifier identifier: String) throws {
        var tokens = try loadPaymentTokens()
        tokens.removeAll { $0.tokenIdentifier == identifier }
        try savePaymentTokens(tokens)
    }
    
    func deleteAllPaymentTokens() throws {
        try localStorage.delete(forKey: StorageKey.paymentTokens)
    }
    
    func hasStoredPaymentTokens() -> Bool {
        return localStorage.exists(forKey: StorageKey.paymentTokens)
    }
    
    // MARK: - Personal Information
    
    func savePersonalInformation(_ info: PersonalInformation) throws {
        let encryptedData = try encrypt(info)
        try localStorage.save(data: encryptedData, forKey: StorageKey.personalInfo)
    }
    
    func loadPersonalInformation() throws -> PersonalInformation {
        let encryptedData = try localStorage.load(forKey: StorageKey.personalInfo)
        return try decrypt(PersonalInformation.self, from: encryptedData)
    }
    
    func deletePersonalInformation() throws {
        try localStorage.delete(forKey: StorageKey.personalInfo)
    }
    
    func hasStoredPersonalInformation() -> Bool {
        return localStorage.exists(forKey: StorageKey.personalInfo)
    }
    
    // MARK: - Custom Keyed Storage
    
    func saveSecureObject<T: Encodable>(_ object: T, forKey key: String) throws {
        let encryptedData = try encrypt(object)
        try localStorage.save(data: encryptedData, forKey: key)
    }
    
    func loadSecureObject<T: Decodable>(_ type: T.Type, forKey key: String) throws -> T {
        let encryptedData = try localStorage.load(forKey: key)
        return try decrypt(type, from: encryptedData)
    }
    
    func deleteSecureObject(forKey key: String) throws {
        try localStorage.delete(forKey: key)
    }
    
    // MARK: - Wipe All Secure Data
    
    func wipeAllSecureData() throws {
        try localStorage.deleteAll()
    }
    
    // MARK: - Rotate Encryption Key
    
    func rotateEncryptionKey() throws {
        // Load all existing data with old key
        let credentials: UserCredentials? = hasStoredCredentials() ? try? loadUserCredentials() : nil
        let tokens: [PaymentToken]? = hasStoredPaymentTokens() ? try? loadPaymentTokens() : nil
        let personalInfo: PersonalInformation? = hasStoredPersonalInformation() ? try? loadPersonalInformation() : nil
        
        // Generate and save new key
        let newKey = try encryptionEngine.generateRandomKey()
        try keychainManager.saveKey(newKey)
        
        // Re-encrypt all data with new key
        if let credentials = credentials {
            try saveUserCredentials(credentials)
        }
        if let tokens = tokens {
            try savePaymentTokens(tokens)
        }
        if let personalInfo = personalInfo {
            try savePersonalInformation(personalInfo)
        }
    }
}

